args.sparql:
SELECT (SUM(?numGoals) AS ?totalGoals)
WHERE {
  ?match wdt:P641 wd:Q93704 ;
         wdt:P585 ?date .
  FILTER(YEAR(?date) = 1971)
  ?match wdt:P641 wd:Q12897 .
  ?match p:P4511 ?goalStatement .
  ?goalStatement pq:P4518 wd:Q12897 ;
                 ps:P4511 ?numGoals .
}

SELECT (SUM(?goals) AS ?totalGoals)
WHERE {
  ?match wdt:P585 ?date .
  ?match p:P710 ?participation .
  ?participation ps:P710 wd:Q12897 ;
                 pq:P10175 wd:Q93704 ;
                 pq:P4518 ?goals .
  FILTER (YEAR(?date) = 1971)
}

SELECT (SUM(?goals) AS ?totalGoals)
WHERE {
  ?match wdt:P641 wd:Q93704 .  # Brazil national team
  ?match wdt:P585 ?date .
  FILTER(YEAR(?date) = 1971)
  ?match p:P4511 ?goalStatement .
  ?goalStatement ps:P4511 ?goals ;
                 pq:P4518 wd:Q12897 .
}
